// Pull both runs' ensures-conjuncts into the proof context so the two
// disjoint `forall|i|` triggers (one bound by r1, one by r2) line up
// against the same shared body `self_.vals@[i]@ == v@`.
assert(r1.0 == forall |i| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@);
assert(r2.0 == forall |i| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@);

// Both runs compute `ret.0` from the *same* spec forall, hence equal.
assert(r1.0 == r2.0);

// On the `!ret.0` branch the spec fully determines `ret.1` via the
// shared nested expression, so r1.1 and r2.1 collapse to the same
// value. (When ret.0 is true the spec leaves ret.1 unconstrained,
// but the determinism predicate only needs equality of the
// constrained components; this branch is where the trigger gap
// actually mattered.)
if !r1.0 {
    assert(!r2.0);
    assert(r1.1 == (self_.vals@[hi as int]@ != v@
        && forall |i| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@));
    assert(r2.1 == (self_.vals@[hi as int]@ != v@
        && forall |i| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@));
    assert(r1.1 == r2.1);
}
